import { motion } from 'framer-motion'

export default function CinematicOverlay() {
  return (
    <div className="fixed inset-0 pointer-events-none z-[9999] overflow-hidden">
      {/* Global Vignette - Optimized */}
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_40%,rgba(0,0,0,0.5)_110%)]" />
      
      {/* Optimized Film Grain Layer (Lower intensity) */}
      <div className="absolute inset-0 bg-noise opacity-[0.03] pointer-events-none" />

      {/* Static Scanlines (Simpler) */}
      <div className="absolute inset-0 bg-scanlines opacity-[0.015] pointer-events-none" />

