import { useEffect, useState } from 'react'
import { motion, useMotionValue, useSpring } from 'framer-motion'

export default function CustomCursor() {
  const mouseX = useMotionValue(0)
  const mouseY = useMotionValue(0)
  const [isHovering, setIsHovering] = useState(false)

  // Much tighter springs for incredibly fast, responsive cursor movement
  const springConfig = { damping: 25, stiffness: 400, mass: 0.5 }
  const springX = useSpring(mouseX, springConfig)
  const springY = useSpring(mouseY, springConfig)

  const innerSpringConfig = { damping: 20, stiffness: 600, mass: 0.2 }
  const innerSpringX = useSpring(mouseX, innerSpringConfig)
  const innerSpringY = useSpring(mouseY, innerSpringConfig)

  useEffect(() => {
    const handleMouseMove = (e) => {
      mouseX.set(e.clientX)
      mouseY.set(e.clientY)
    }

    const handleMouseOver = (e) => {
      if (
        e.target.tagName === 'A' ||
        e.target.tagName === 'BUTTON' ||
        e.target.closest('button') ||
        e.target.classList.contains('interactive')
      ) {
        setIsHovering(true)
      } else {
        setIsHovering(false)
      }
    }

    window.addEventListener('mousemove', handleMouseMove)
    window.addEventListener('mouseover', handleMouseOver)

    return () => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('mouseover', handleMouseOver)
    }
  }, [mouseX, mouseY])

  return (
    <>
      {/* Small Dot */}
      <motion.div
        style={{
          x: innerSpringX,
          y: innerSpringY,
          translateX: '-50%',
          translateY: '-50%',
        }}
        className="fixed top-0 left-0 w-1.5 h-1.5 bg-white rounded-full z-[9999] pointer-events-none mix-blend-difference"
      />
      
      {/* Large Reacting Ring */}
      <motion.div
        style={{
          x: springX,
          y: springY,
          translateX: '-50%',
          translateY: '-50%',
        }}
        animate={{
          scale: isHovering ? 2 : 1,
          opacity: isHovering ? 0.3 : 0.6,
          borderWidth: isHovering ? '1px' : '2px',
        }}
        transition={{ type: 'spring', ...springConfig }}
        className="fixed top-0 left-0 w-8 h-8 border-white rounded-full z-[9998] pointer-events-none mix-blend-difference"
      />
    </>
  )
}

import { motion } from 'framer-motion'

export default function GlitchText({ text, className }) {
  return (
    <div className={`relative inline-block ${className}`} data-text={text}>
      {/* Base Layer */}
      <span className="relative z-10 text-white">
        {text}
      </span>
      
      {/* RGB Glitch Layers */}
      <span className="absolute top-0 left-0 w-full h-full text-red-500/50 mix-blend-screen opacity-0 group-hover:opacity-100 transition-opacity duration-100 animate-[glitch-anim_0.2s_infinite] pointer-events-none">
        {text}
      </span>
      <span className="absolute top-0 left-0 w-full h-full text-cyan-500/50 mix-blend-screen opacity-0 group-hover:opacity-100 transition-opacity duration-100 animate-[glitch-anim_0.2s_infinite_reverse] pointer-events-none">
        {text}
      </span>
    </div>
  )
}

import { motion, useScroll, useTransform } from 'framer-motion'
import AnimatedHeading from './AnimatedHeading'
import CTAButton from './CTAButton'
import { useRef } from 'react'

export default function Hero({ onEnterClick }) {
  const ref = useRef(null)
  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ["start start", "end start"]
  })

  const y = useTransform(scrollYProgress, [0, 1], ["0%", "50%"])
  const opacity = useTransform(scrollYProgress, [0, 0.5], [1, 0])
  const scale = useTransform(scrollYProgress, [0, 1], [1, 0.9])

  return (
    <section 
      ref={ref}
      style={{ position: 'relative' }}
      className="relative min-h-screen flex items-center justify-center select-none"
    >
      {/* Soft Glow Ambient Background */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full -z-10 flex items-center justify-center">
        <div className="w-[800px] h-[800px] radial-glow opacity-20 animate-pulse transition-opacity duration-1000" />
      </div>

      <motion.div 
        style={{ y, opacity, scale }}
        className="max-w-7xl mx-auto px-8 flex flex-col items-center text-center"
      >
        {/* Cinematic Headline - Agency Brand */}
        <div className="mb-0 relative flex justify-center w-full z-20">
           <AnimatedHeading text="VELTRIX" />
        </div>

        {/* Tactical Interface Lines */}
        <motion.div 
          initial={{ scaleX: 0, opacity: 0 }}
          animate={{ scaleX: 1, opacity: 0.2 }}
          transition={{ duration: 1.5, delay: 1, ease: "easeOut" }}
          className="mt-4 flex items-center space-x-4"
        >
           <div className="h-[1px] w-12 bg-white origin-right" />
           <div className="w-1.5 h-1.5 border border-white rotate-45" />
           <div className="h-[1px] w-12 bg-white origin-left" />
        </motion.div>

        {/* CTA Launch */}
        <motion.div
          initial={{ opacity: 0, y: 30, scale: 0.9 }}
          animate={{ opacity: 1, y: 0, scale: 1 }}
          transition={{ duration: 1.2, delay: 1.5, ease: [0.16, 1, 0.3, 1] }}
          className="mt-16 z-20"
        >
          <CTAButton onClick={onEnterClick} />
        </motion.div>
      </motion.div>

      {/* Decorative Animated Lines */}
      <div className="absolute bottom-16 left-0 w-full h-[1px] bg-gradient-to-r from-transparent via-white/5 to-transparent z-10" />
      <div className="absolute top-1/2 left-0 w-[1px] h-32 bg-gradient-to-b from-transparent via-white/10 to-transparent z-10 animate-pulse" />
    </section>
  )
}

import { useRef, useState } from 'react'
import { motion } from 'framer-motion'

export default function Magnetic({ children, strength = 20 }) {
  const ref = useRef(null)
  const [position, setPosition] = useState({ x: 0, y: 0 })

  const handleMouseMove = (e) => {
    const { clientX, clientY } = e
    const { width, height, left, top } = ref.current.getBoundingClientRect()
    const x = clientX - (left + width / 2)
    const y = clientY - (top + height / 2)
    setPosition({ x: x * (strength / 100), y: y * (strength / 100) })
  }

  const handleMouseLeave = () => {
    setPosition({ x: 0, y: 0 })
  }

  return (
    <motion.div
      ref={ref}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      animate={{ x: position.x, y: position.y }}
      transition={{ type: 'spring', stiffness: 150, damping: 15, mass: 0.1 }}
      className="inline-block"
    >
      {children}
    </motion.div>
  )
}

import { motion, AnimatePresence } from 'framer-motion'
import { useState } from 'react'
import Magnetic from './Magnetic'
import { Menu, X } from 'lucide-react'

export default function Navbar() {
  const [isOpen, setIsOpen] = useState(false)
  const links = ['Products', 'About', 'Contact']

  return (
    <>
      <motion.nav 
        initial={{ y: -100, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 1.2, ease: [0.16, 1, 0.3, 1] }}
        className="fixed top-0 left-0 w-full z-[100] px-6 py-6 md:px-12 md:py-8"
      >
        <div className="max-w-7xl mx-auto flex items-center justify-between">
          {/* Logo Section */}
          <Magnetic strength={20}>
            <motion.div 
              whileHover={{ scale: 1.05 }}
              className="flex items-center space-x-3 cursor-pointer group p-2 interactive"
            >
              <div className="w-8 h-8 rounded-lg glass flex items-center justify-center rotate-45 group-hover:rotate-[225deg] transition-transform duration-700">
                <div className="w-4 h-4 bg-white -rotate-45" />
              </div>
              <span className="font-heading font-black text-xl tracking-[0.2em] uppercase text-white">
                Veltrix <span className="text-white/40 group-hover:text-white transition-colors duration-500">Labs</span>
              </span>
            </motion.div>
          </Magnetic>

          {/* Desktop Links */}
          <div className="hidden md:flex space-x-12">
            {links.map((link, i) => (
              <Magnetic key={link} strength={30}>
                <motion.a
                  href={`#${link.toLowerCase()}`}
                  initial={{ opacity: 0, y: -20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.5 + i * 0.1, duration: 0.8 }}
                  className="text-[10px] font-bold tracking-[0.5em] uppercase text-white/40 hover:text-white transition-all duration-500 relative group p-2 interactive inline-block"
                >
                  <span className="relative z-10">{link}</span>
                  <span className="absolute -bottom-2 left-0 w-0 h-[1px] bg-white transition-all duration-500 group-hover:w-full opacity-50" />
                </motion.a>
              </Magnetic>
            ))}
          </div>
          
          {/* Menu Icon for Mobile */}
          <div 
            className="md:hidden glass p-3 rounded-xl interactive cursor-pointer text-white/60 hover:text-white transition-colors"
            onClick={() => setIsOpen(!isOpen)}
          >
            {isOpen ? <X size={20} /> : <Menu size={20} />}
          </div>
        </div>
      </motion.nav>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, x: '100%' }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: '100%' }}
            transition={{ type: 'spring', damping: 25, stiffness: 200 }}
            className="fixed inset-0 z-[90] bg-black/95 backdrop-blur-2xl md:hidden flex flex-col items-center justify-center space-y-8"
          >
            {links.map((link, i) => (
              <motion.a
                key={link}
                href={`#${link.toLowerCase()}`}
                onClick={() => setIsOpen(false)}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.1 + i * 0.1 }}
                className="text-4xl font-black text-white/40 hover:text-white uppercase tracking-tighter transition-colors"
              >
                {link}
              </motion.a>
            ))}
          </motion.div>
        )}
      </AnimatePresence>
    </>
  )
}

import { useRef, useMemo, useEffect } from 'react'
import { Canvas, useFrame, useThree } from '@react-three/fiber'
import { PerspectiveCamera, Float } from '@react-three/drei'
import * as THREE from 'three'
import { EffectComposer, Bloom, ChromaticAberration, DepthOfField } from '@react-three/postprocessing'
import { BlendFunction } from 'postprocessing'

const THEME_COLORS = ['#FFD700', '#ADFF2F', '#00CED1', '#1E90FF']

const ConstellationParticles = ({ count = 120 }) => { // Reduced count for better performance
  const pointsRef = useRef()
  const linesRef = useRef()
  const { viewport, mouse } = useThree()
  const shockwaves = useRef([])

  useEffect(() => {
    const handleClick = () => {
      shockwaves.current.push({
        x: (mouse.x * viewport.width) / 2,
        y: (mouse.y * viewport.height) / 2,
        radius: 0,
        opacity: 1,
        active: true
      })
    }
    window.addEventListener('mousedown', handleClick)
    return () => window.removeEventListener('mousedown', handleClick)
  }, [mouse, viewport])

  const particles = useMemo(() => {
    const temp = []
    for (let i = 0; i < count; i++) {
        temp.push({
            x: THREE.MathUtils.randFloatSpread(100),
            y: THREE.MathUtils.randFloatSpread(80),
            z: THREE.MathUtils.randFloatSpread(50),
            speed: Math.random() * 0.015 + 0.005,
            phase: Math.random() * Math.PI * 2,
            baseX: 0, baseY: 0, baseZ: 0
        })
    }
    temp.forEach(p => { p.baseX = p.x; p.baseY = p.y; p.baseZ = p.z })
    return temp
  }, [count])

  const maxLines = count * 6 // Optimized limit
  const [positions, colors, linePositions, lineColors] = useMemo(() => {
    return [
      new Float32Array(count * 3),
      new Float32Array(count * 3).fill(1),
      new Float32Array(maxLines * 6),
      new Float32Array(maxLines * 6)
    ]
  }, [count, maxLines])

  useFrame((state) => {
    const clockTime = state.clock.getElapsedTime()
    const mouseX = (mouse.x * viewport.width) / 2
    const mouseY = (mouse.y * viewport.height) / 2
    const scrollOffset = window.scrollY * 0.02
    let lineIndex = 0

    shockwaves.current.forEach(wave => {
      if (wave.active) {
        wave.radius += 2.0 
        wave.opacity -= 0.02 
        if (wave.opacity <= 0) wave.active = false
      }
    })
    shockwaves.current = shockwaves.current.filter(w => w.active)

    for (let i = 0; i < count; i++) {
      const p = particles[i]
      p.x += Math.sin(clockTime * p.speed + p.phase) * 0.03
      p.y += Math.cos(clockTime * p.speed + p.phase) * 0.03
      p.x += (p.baseX - p.x) * 0.005
      p.y += (p.baseY - p.y) * 0.005

      const dx = mouseX - p.x
      const dy = mouseY - (p.y + scrollOffset)
      const distSq = dx * dx + dy * dy
      
      if (distSq < 225 && distSq > 0.01) { // 15^2
        const dist = Math.sqrt(distSq)
        const force = (15 - dist) / 15
        p.x -= (dx / dist) * force * 5
        p.y -= (dy / dist) * force * 5
      }

      positions[i * 3] = p.x
      positions[i * 3 + 1] = p.y + scrollOffset
      positions[i * 3 + 2] = p.z

      // Optimized connection check (Limited distance and max lines)
      if (lineIndex < maxLines - 1) {
        for (let j = i + 1; j < count; j++) {
          const p2 = particles[j]
          const ddx = p.x - p2.x
          const ddy = p.y - p2.y
          const ddistSq = ddx * ddx + ddy * ddy
          
          if (ddistSq < 100) { // 10^2
            const ddist = Math.sqrt(ddistSq)
            const alpha = 1.0 - (ddist / 10)
            
            linePositions[lineIndex * 3] = p.x
            linePositions[lineIndex * 3 + 1] = p.y + scrollOffset
            linePositions[lineIndex * 3 + 2] = p.z
            lineColors[lineIndex * 3] = lineColors[lineIndex * 3 + 1] = lineColors[lineIndex * 3 + 2] = 0.5 * alpha
            lineIndex++

            linePositions[lineIndex * 3] = p2.x
            linePositions[lineIndex * 3 + 1] = p2.y + scrollOffset
            linePositions[lineIndex * 3 + 2] = p2.z
            lineColors[lineIndex * 3] = lineColors[lineIndex * 3 + 1] = lineColors[lineIndex * 3 + 2] = 0.5 * alpha
            lineIndex++
            
            if (lineIndex >= maxLines) break
          }
        }
      }
    }

    if (pointsRef.current) pointsRef.current.geometry.attributes.position.needsUpdate = true
    if (linesRef.current) {
        linesRef.current.geometry.setDrawRange(0, lineIndex)
        linesRef.current.geometry.attributes.position.needsUpdate = true
        linesRef.current.geometry.attributes.color.needsUpdate = true
    }
  })

  return (
    <group>
      <points ref={pointsRef}>
        <bufferGeometry>
          <bufferAttribute attach="attributes-position" count={count} array={positions} itemSize={3} />
          <bufferAttribute attach="attributes-color" count={count} array={colors} itemSize={3} />
        </bufferGeometry>
        <pointsMaterial size={0.25} vertexColors transparent opacity={0.4} blending={THREE.AdditiveBlending} />
      </points>
      <lineSegments ref={linesRef}>
        <bufferGeometry>
           <bufferAttribute attach="attributes-position" count={maxLines * 2} array={linePositions} itemSize={3} />
           <bufferAttribute attach="attributes-color" count={maxLines * 2} array={lineColors} itemSize={3} />
        </bufferGeometry>
        <lineBasicMaterial vertexColors transparent opacity={0.3} blending={THREE.AdditiveBlending} />
      </lineSegments>
    </group>
  )
}

function Atmosphere() {
  return (
    <>
      <ambientLight intensity={0.15} />
      <Float speed={0.5} rotationIntensity={0.1} floatIntensity={0.1}>
        <mesh position={[0, -45, -50]}>
          <sphereGeometry args={[40, 32, 32]} />
          <meshBasicMaterial color="#ffffff" wireframe transparent opacity={0.02} />
        </mesh>
      </Float>
    </>
  )
}

export default function ParticleBackground() {
  return (
    <div className="w-full h-full bg-black">
      <Canvas dpr={[1, 1.5]} gl={{ antialias: false, powerPreference: "high-performance" }}>
        <PerspectiveCamera makeDefault position={[0, 0, 70]} fov={75} />
        <ConstellationParticles />
        <Atmosphere />
        <fog attach="fog" args={['#000000', 30, 150]} />
        <EffectComposer disableNormalPass multisampling={0}>
          <Bloom luminanceThreshold={0.5} intensity={0.8} />
          <ChromaticAberration offset={[0.001, 0.001]} />
        </EffectComposer>
      </Canvas>
    </div>
  )
}

import { motion, useScroll, useTransform } from 'framer-motion'
import { useRef } from 'react'

export default function ProductShowcase() {
  const containerRef = useRef(null)
  const { scrollYProgress } = useScroll({
    target: containerRef,
    offset: ["start end", "end start"]
  })

  const y = useTransform(scrollYProgress, [0, 1], [-100, 100])
  const scale = useTransform(scrollYProgress, [0, 0.5, 1], [0.8, 1, 0.8])

  return (
    <section 
      ref={containerRef}
      className="min-h-screen py-20 md:py-32 px-6 md:px-10 relative z-10 max-w-7xl mx-auto w-full flex flex-col items-center justify-center overflow-hidden"
    >
      <motion.div 
        initial={{ opacity: 0, y: 30 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
